#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding gerontology-assessment (15 tables)..."

cargo loco generate scaffold patient \
    first_name:string! \
    last_name:string! \
    date_of_birth:date! \
    nhs_number:string^ \
    sex:string! \
    weight_kg:double \
    height_cm:double \
    bmi:double \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    --htmx

cargo loco generate scaffold assessment_demographics \
    assessment:references \
    ethnicity:string! \
    primary_language:string! \
    interpreter_required:string! \
    marital_status:string! \
    living_situation:string! \
    next_of_kin_name:string! \
    next_of_kin_phone:string! \
    next_of_kin_relationship:string! \
    has_lasting_power_of_attorney:string! \
    gp_name:string! \
    gp_practice:string! \
    --htmx

cargo loco generate scaffold assessment_functional_assessment \
    assessment:references \
    bathing_independence:string! \
    dressing_independence:string! \
    toileting_independence:string! \
    transferring_independence:string! \
    feeding_independence:string! \
    continence_status:string! \
    cooking_ability:string! \
    shopping_ability:string! \
    housework_ability:string! \
    medication_management:string! \
    telephone_use:string! \
    finances_management:string! \
    barthel_index_score:int \
    additional_functional_notes:text! \
    --htmx

cargo loco generate scaffold assessment_cognitive_screen \
    assessment:references \
    mmse_score:int \
    moca_score:int \
    clock_drawing_score:int \
    orientation_to_time:string! \
    orientation_to_place:string! \
    short_term_memory:string! \
    long_term_memory:string! \
    executive_function:string! \
    language_function:string! \
    known_dementia_diagnosis:string! \
    dementia_type:string! \
    delirium_screen:string! \
    cognitive_decline_reported_by:string! \
    cognitive_notes:text! \
    --htmx

cargo loco generate scaffold assessment_mobility_and_falls \
    assessment:references \
    mobility_level:string! \
    mobility_aid_type:string! \
    gait_abnormality:string! \
    gait_abnormality_details:text! \
    timed_up_and_go_seconds:double \
    history_of_falls:string! \
    falls_in_last_12_months:int \
    fall_related_injury:string! \
    fall_injury_details:text! \
    fear_of_falling:string! \
    balance_impairment:string! \
    postural_hypotension:string! \
    home_hazards_identified:string! \
    home_hazard_details:text! \
    mobility_notes:text! \
    --htmx

cargo loco generate scaffold assessment_nutrition \
    assessment:references \
    unintentional_weight_loss:string! \
    weight_loss_amount_kg:double \
    weight_loss_duration_months:int \
    appetite:string! \
    meals_per_day:int \
    meal_preparation:string! \
    dietary_restrictions:text! \
    swallowing_difficulty:string! \
    swallowing_details:text! \
    denture_status:string! \
    hydration_status:string! \
    must_score:int \
    nutritional_supplement:string! \
    supplement_details:text! \
    nutrition_notes:text! \
    --htmx

cargo loco generate scaffold assessment_polypharmacy_review \
    assessment:references \
    total_regular_medications:int \
    total_prn_medications:int \
    polypharmacy_flag:string! \
    medication_review_date:date \
    falls_risk_medications:string! \
    falls_risk_medication_details:text! \
    anticholinergic_burden:string! \
    drug_interactions_identified:string! \
    drug_interaction_details:text! \
    adherence_concerns:string! \
    adherence_details:text! \
    stopp_start_review_done:string! \
    deprescribing_opportunities:text! \
    polypharmacy_notes:text! \
    --htmx

cargo loco generate scaffold assessment_polypharmacy_review_medication \
    polypharmacy_review:references \
    medication_name:string! \
    dose:string! \
    frequency:string! \
    route:string! \
    indication:string! \
    is_prn:string! \
    sort_order:int! \
    --htmx

cargo loco generate scaffold assessment_comorbidities \
    assessment:references \
    has_hypertension:string! \
    has_diabetes:string! \
    diabetes_type:string! \
    has_heart_failure:string! \
    has_atrial_fibrillation:string! \
    has_copd:string! \
    has_osteoporosis:string! \
    has_osteoarthritis:string! \
    has_chronic_kidney_disease:string! \
    ckd_stage:string! \
    has_stroke_history:string! \
    has_parkinson_disease:string! \
    has_cancer:string! \
    cancer_details:text! \
    charlson_comorbidity_index:int \
    other_comorbidities:text! \
    comorbidity_notes:text! \
    --htmx

cargo loco generate scaffold assessment_psychosocial \
    assessment:references \
    mood_screen:string! \
    geriatric_depression_scale_score:int \
    anxiety_present:string! \
    social_isolation:string! \
    loneliness:string! \
    social_activities_participation:string! \
    carer_available:string! \
    carer_relationship:string! \
    carer_stress:string! \
    carer_stress_details:text! \
    bereavement:string! \
    bereavement_details:text! \
    financial_concerns:string! \
    elder_abuse_concerns:string! \
    safeguarding_referral_needed:string! \
    psychosocial_notes:text! \
    --htmx

cargo loco generate scaffold assessment_continence_and_skin \
    assessment:references \
    urinary_incontinence:string! \
    urinary_incontinence_type:string! \
    urinary_frequency:string! \
    nocturia:int \
    catheter_in_situ:string! \
    faecal_incontinence:string! \
    constipation:string! \
    bowel_pattern:string! \
    skin_integrity:string! \
    pressure_ulcer:string! \
    pressure_ulcer_grade:string! \
    pressure_ulcer_location:string! \
    waterlow_score:int \
    skin_tears:string! \
    leg_ulcers:string! \
    moisture_associated_skin_damage:string! \
    continence_skin_notes:text! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    cfs_score:int! \
    cfs_category:string! \
    functional_domain_score:int \
    cognitive_domain_score:int \
    mobility_domain_score:int \
    nutrition_domain_score:int \
    polypharmacy_domain_score:int \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    cfs_contribution:int! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
